SELECT count(*) FROM hm_query.fulfillment_flat

    AND order_id = #{orderId}
    AND warehouse_id = #{warehouseId}
    AND user_id = #{userId}
    AND priority = #{priority}
    AND fulfillment_type = #{fulfillmentType}
    AND carrier = #{carrier}
    AND state_id = #{stateId}
    AND tracking_number = #{trackingNumber}
    AND (
        order_id LIKE CONCAT('%', #{q}, '%')
        OR tracking_number LIKE CONCAT('%', #{q}, '%')
        OR warehouse_name LIKE CONCAT('%', #{q}, '%')
        OR carrier LIKE CONCAT('%', #{q}, '%')
    )

SELECT id, order_id as "orderId", warehouse_id as "warehouseId", warehouse_name as "warehouseName", user_id as "userId", saga_id as "sagaId", priority, fulfillment_type as "fulfillmentType", shipping_method as "shippingMethod", carrier, tracking_number as "trackingNumber", total_items as "totalItems", state_id as "stateId", flow_id as "flowId", estimated_ship_date as "estimatedShipDate", estimated_delivery_date as "estimatedDeliveryDate", created_time as "createdTime" FROM hm_query.fulfillment_flat
AND order_id = #{orderId} AND warehouse_id = #{warehouseId} AND user_id = #{userId} AND priority = #{priority} AND fulfillment_type = #{fulfillmentType} AND carrier = #{carrier} AND state_id = #{stateId} AND tracking_number = #{trackingNumber} AND ( order_id LIKE CONCAT('%', #{q}, '%') OR tracking_number LIKE CONCAT('%', #{q}, '%') OR warehouse_name LIKE CONCAT('%', #{q}, '%') OR carrier LIKE CONCAT('%', #{q}, '%') )
${orderby} ${pagination}

SELECT count(*) FROM hm_query.fulfillment_flat
WHERE warehouse_id = #{warehouseId}
AND state_id = #{stateId}
